(function () {
    'use strict';

    const AI_WBR_INSTANCE_KEY = '__AI_WORLDBOOK_ROUTER_USERSCRIPT_LOADED__';

    function getHostWindow() {
        try {
            if (window.parent && window.parent !== window && window.parent.document) {
                return window.parent;
            }
        } catch (_) {}
        return window;
    }

    const hostWindow = getHostWindow();
    const hostDocument = hostWindow.document;
    if (!hostDocument || hostWindow[AI_WBR_INSTANCE_KEY]) {
        return;
    }
    hostWindow[AI_WBR_INSTANCE_KEY] = true;

    const moduleSource = "\nconst hostWindow = window;\nconst hostDocument = document;\nconst AI_WBR_SETTINGS_HTML = \"<div id=\\\"ai_worldbook_router_settings\\\" class=\\\"ai-worldbook-router-settings\\\">\\r\\n    <div class=\\\"inline-drawer\\\">\\r\\n        <div class=\\\"inline-drawer-toggle inline-drawer-header\\\">\\r\\n            <b>世界书读取</b>\\r\\n            <div class=\\\"inline-drawer-icon fa-solid fa-circle-chevron-down down\\\"></div>\\r\\n        </div>\\r\\n        <div class=\\\"inline-drawer-content\\\">\\r\\n            <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_enabled\\\">\\r\\n                <input id=\\\"ai_wbr_enabled\\\" type=\\\"checkbox\\\" />\\r\\n                <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"总开关。开启后会在正式生成前筛选本轮相关世界书并注入 prompt。\\\"></span>\\r\\n                <span>启用前置 AI 世界书路由</span>\\r\\n            </label>\\r\\n            <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_debug\\\">\\r\\n                <input id=\\\"ai_wbr_debug\\\" type=\\\"checkbox\\\" />\\r\\n                <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"在浏览器控制台和本面板显示候选、选择原因与注入长度，方便排查。\\\"></span>\\r\\n                <span>调试模式</span>\\r\\n            </label>\\r\\n            <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_keyword_recall\\\">\\r\\n                <input id=\\\"ai_wbr_keyword_recall\\\" type=\\\"checkbox\\\" />\\r\\n                <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"用最后用户消息、最近上下文和可选状态匹配世界书 keys，先缩小候选范围。推荐开启。\\\"></span>\\r\\n                <span>启用关键词粗召回</span>\\r\\n            </label>\\r\\n            <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_use_mvu\\\">\\r\\n                <input id=\\\"ai_wbr_use_mvu\\\" type=\\\"checkbox\\\" />\\r\\n                <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"尝试把变量卡表格、MVU、Tavern Helper 等状态数据纳入读取范围，并把地点、NPC、阶段等状态加入匹配与判断。读不到会静默跳过。\\\"></span>\\r\\n                <span>变量卡表格纳入读取范围</span>\\r\\n            </label>\\r\\n            <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_allow_constant\\\">\\r\\n                <input id=\\\"ai_wbr_allow_constant\\\" type=\\\"checkbox\\\" />\\r\\n                <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"默认跳过 constant 条目，避免和原生世界书常驻注入重复。开启后，本插件也会把常驻条目读进候选范围。\\\"></span>\\r\\n                <span>允许读取常驻条目</span>\\r\\n            </label>\\r\\n\\r\\n            <div class=\\\"m-t-1\\\">\\r\\n                <label><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"这里显示当前聊天/角色下实际生效的世界书。勾选表示允许参与前置召回；取消勾选后，这本世界书将不会被本插件搜索。\\\"></span>当前生效世界书</label>\\r\\n                <div id=\\\"ai_wbr_active_world_items\\\" class=\\\"ai-wbr-world-list\\\"></div>\\r\\n            </div>\\r\\n\\r\\n            <div class=\\\"m-t-1\\\">\\r\\n                <label for=\\\"ai_wbr_title_block_input\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"按标题拦截世界书条目。输入一个标题关键词后点添加；命中的条目不会进入本插件的候选、AI 选择和注入。\\\"></span>标题拦截规则</label>\\r\\n                <div class=\\\"ai-wbr-token-editor\\\">\\r\\n                    <input id=\\\"ai_wbr_title_block_input\\\" class=\\\"text_pole\\\" type=\\\"text\\\" placeholder=\\\"例如：TavernDB-ACU-WrapperEnd\\\" />\\r\\n                    <button id=\\\"ai_wbr_title_block_add\\\" class=\\\"menu_button\\\" type=\\\"button\\\">添加</button>\\r\\n                </div>\\r\\n                <div id=\\\"ai_wbr_title_block_items\\\" class=\\\"ai-wbr-token-list\\\"></div>\\r\\n            </div>\\r\\n\\r\\n            <div class=\\\"ai-wbr-section\\\">\\r\\n                <div class=\\\"ai-wbr-section-title\\\">\\r\\n                    <b>独立路由模型</b>\\r\\n                </div>\\r\\n                <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_router_use_separate_model\\\">\\r\\n                    <input id=\\\"ai_wbr_router_use_separate_model\\\" type=\\\"checkbox\\\" />\\r\\n                    <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"开启后，前置 AI 精选不走当前主模型，而走下面单独配置的 OpenAI-compatible 接口。\\\"></span>\\r\\n                    <span>启用独立模型</span>\\r\\n                </label>\\r\\n\\r\\n                <div class=\\\"ai-wbr-grid\\\">\\r\\n                    <label for=\\\"ai_wbr_router_api_url\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"独立路由模型的接口地址。通常填到 /v1，例如 http://127.0.0.1:8000/v1 。\\\"></span>API URL</label>\\r\\n                    <input id=\\\"ai_wbr_router_api_url\\\" class=\\\"text_pole\\\" type=\\\"text\\\" placeholder=\\\"https://example.com/v1\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_router_api_key\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"用于拉取模型和执行前置 AI 选择的 API Key，仅保存在此插件设置里。\\\"></span>API Key</label>\\r\\n                    <input id=\\\"ai_wbr_router_api_key\\\" class=\\\"text_pole\\\" type=\\\"password\\\" placeholder=\\\"sk-...\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_router_model\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"当前用于前置世界书精选的模型。先点“拉取模型”，再从下拉里选择。\\\"></span>路由模型</label>\\r\\n                    <select id=\\\"ai_wbr_router_model\\\" class=\\\"text_pole\\\">\\r\\n                        <option value=\\\"\\\">未选择</option>\\r\\n                    </select>\\r\\n                </div>\\r\\n\\r\\n                <div class=\\\"ai-wbr-actions\\\">\\r\\n                    <button id=\\\"ai_wbr_fetch_models\\\" class=\\\"menu_button\\\">拉取模型</button>\\r\\n                    <span id=\\\"ai_wbr_router_status\\\" class=\\\"ai-wbr-status\\\">未连接</span>\\r\\n                </div>\\r\\n            </div>\\r\\n\\r\\n            <div class=\\\"ai-wbr-grid\\\">\\r\\n                <label for=\\\"ai_wbr_max_candidates\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"本插件先用本地规则从世界书里召回候选，再把候选交给前置 AI 精选。这里控制候选上限。\\\"></span>最大候选条目数</label>\\r\\n                <input id=\\\"ai_wbr_max_candidates\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"1\\\" max=\\\"100\\\" step=\\\"1\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_max_selected\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"前置 AI 或 fallback 最多选择多少条注入本轮 prompt。\\\"></span>最终注入条目数</label>\\r\\n                <input id=\\\"ai_wbr_max_selected\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"1\\\" max=\\\"50\\\" step=\\\"1\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_max_chars\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"最终世界书注入块的字符上限，防止条目过长挤占上下文。\\\"></span>最大注入字符数</label>\\r\\n                <input id=\\\"ai_wbr_max_chars\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"100\\\" max=\\\"30000\\\" step=\\\"100\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_scan_messages\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"用于关键词匹配和 AI 判断的最近聊天消息数量。剧情连续时可适当调高。\\\"></span>扫描最近消息数</label>\\r\\n                <input id=\\\"ai_wbr_scan_messages\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"1\\\" max=\\\"50\\\" step=\\\"1\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_main_history_ai_turns\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"限制主模型正式生成时保留的历史 AI 回复楼数。仅计算 assistant 回复，不计算用户消息；角色卡、破限、系统提示、世界书注入不受影响。填 0 表示不限制。\\\"></span>主模型历史AI楼层数</label>\\r\\n                <input id=\\\"ai_wbr_main_history_ai_turns\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"0\\\" max=\\\"100\\\" step=\\\"1\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_position\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"控制筛选出的世界书块插入 prompt 的位置。通常推荐 In-chat 深度注入。\\\"></span>注入位置</label>\\r\\n                <select id=\\\"ai_wbr_position\\\" class=\\\"text_pole\\\">\\r\\n                    <option value=\\\"1\\\">In-chat 深度注入</option>\\r\\n                    <option value=\\\"0\\\">故事字符串后</option>\\r\\n                    <option value=\\\"2\\\">故事字符串前</option>\\r\\n                </select>\\r\\n\\r\\n                <label for=\\\"ai_wbr_depth\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"In-chat 注入时距离最新消息的深度。数字越小通常越靠近最新上下文，影响越强。\\\"></span>注入深度</label>\\r\\n                <input id=\\\"ai_wbr_depth\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"0\\\" max=\\\"1000\\\" step=\\\"1\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_role\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"In-chat 注入使用的消息角色。一般推荐 system。\\\"></span>In-chat 角色</label>\\r\\n                <select id=\\\"ai_wbr_role\\\" class=\\\"text_pole\\\">\\r\\n                    <option value=\\\"0\\\">system</option>\\r\\n                    <option value=\\\"1\\\">user</option>\\r\\n                    <option value=\\\"2\\\">assistant</option>\\r\\n                </select>\\r\\n\\r\\n                <label for=\\\"ai_wbr_ai_response_length\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"限制前置 AI 输出 JSON 的最大长度。这里只做插件侧保护，不强行卡死在 1024。候选很多或某些接口吞吐保守时可调高。\\\"></span>AI 判定最大回复 tokens</label>\\r\\n                <input id=\\\"ai_wbr_ai_response_length\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"32\\\" max=\\\"16384\\\" step=\\\"16\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_router_retries\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"当前置 AI 调用或 JSON 解析失败时，额外自动重试几次。重试时会抛出反转标记；全部失败时会抛出红色 × 并红光闪三下。\\\"></span>前置 AI 重试次数</label>\\r\\n                <input id=\\\"ai_wbr_router_retries\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"0\\\" max=\\\"5\\\" step=\\\"1\\\" />\\r\\n\\r\\n                <label for=\\\"ai_wbr_router_request_max_tokens\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"前置世界书路由请求实际发送给模型的 max_tokens 上限。独立模型和非独立模型都使用这个值。\\\"></span>前置请求 tokens 上限</label>\\r\\n                <input id=\\\"ai_wbr_router_request_max_tokens\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"32\\\" max=\\\"100000\\\" step=\\\"16\\\" />\\r\\n            </div>\\r\\n\\r\\n            <div class=\\\"m-t-1\\\">\\r\\n                <label for=\\\"ai_wbr_system_prompt\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"约束前置 AI 如何选择条目以及必须输出严格 JSON。通常不用改。\\\"></span>前置 AI 系统提示</label>\\r\\n                <textarea id=\\\"ai_wbr_system_prompt\\\" class=\\\"text_pole textarea_compact ai-wbr-prompt\\\" rows=\\\"5\\\"></textarea>\\r\\n            </div>\\r\\n\\r\\n            <div class=\\\"ai-wbr-section\\\" id=\\\"ai_wbr_memory_section\\\">\\r\\n                <div class=\\\"ai-wbr-section-title\\\">\\r\\n                    <b>后置轻量记忆图谱</b>\\r\\n                </div>\\r\\n                <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_memory_enabled\\\">\\r\\n                    <input id=\\\"ai_wbr_memory_enabled\\\" type=\\\"checkbox\\\" />\\r\\n                    <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"在主回复完成后调用一次轻量总结，把长期有价值的信息写入可视化记忆图谱。\\\"></span>\\r\\n                    <span>启用后置记忆整理</span>\\r\\n                </label>\\r\\n                <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_memory_auto_run\\\">\\r\\n                    <input id=\\\"ai_wbr_memory_auto_run\\\" type=\\\"checkbox\\\" />\\r\\n                    <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"开启后每次正式回复结束自动整理一次；也可以关闭后用“立即整理本轮”手动触发。\\\"></span>\\r\\n                    <span>回复结束后自动整理</span>\\r\\n                </label>\\r\\n                <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_memory_inject_to_router\\\">\\r\\n                    <input id=\\\"ai_wbr_memory_inject_to_router\\\" type=\\\"checkbox\\\" />\\r\\n                    <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"把当前记忆状态摘要加入前置世界书路由输入，帮助下一轮更稳定命中相关条目。\\\"></span>\\r\\n                    <span>记忆状态参与世界书路由</span>\\r\\n                </label>\\r\\n                <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_memory_debug\\\">\\r\\n                    <input id=\\\"ai_wbr_memory_debug\\\" type=\\\"checkbox\\\" />\\r\\n                    <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"显示后置记忆整理发给 AI 的 Prompt、AI 原始返回和解析错误，方便排查。\\\"></span>\\r\\n                    <span>记忆调试模式</span>\\r\\n                </label>\\r\\n                <label class=\\\"checkbox_label\\\" for=\\\"ai_wbr_memory_scope_debug\\\">\\r\\n                    <input id=\\\"ai_wbr_memory_scope_debug\\\" type=\\\"checkbox\\\" />\\r\\n                    <span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"在浏览器控制台输出切卡/切聊天、读取记忆、保存记忆和面板重绘的详细日志。\\\"></span>\\r\\n                    <span>记忆作用域控制台调试</span>\\r\\n                </label>\\r\\n\\r\\n                <div class=\\\"ai-wbr-grid\\\">\\r\\n                    <label for=\\\"ai_wbr_memory_auto_run_interval\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"开启自动整理时，每隔多少条聊天消息触发一次。填 1 表示每轮都整理；填 20 表示每 20 条聊天楼层整理一次。\\\"></span>自动整理间隔消息数</label>\\r\\n                    <input id=\\\"ai_wbr_memory_auto_run_interval\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"1\\\" max=\\\"100\\\" step=\\\"1\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_memory_scan_messages\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"后置记忆整理读取最近多少条聊天消息。只用于总结，不影响主模型历史楼层限制。\\\"></span>记忆整理读取消息数</label>\\r\\n                    <input id=\\\"ai_wbr_memory_scan_messages\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"2\\\" max=\\\"40\\\" step=\\\"1\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_memory_max_nodes\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"记忆图谱最多保留多少个节点，超出后优先保留重要度较高、最近更新的节点。\\\"></span>最大记忆节点数</label>\\r\\n                    <input id=\\\"ai_wbr_memory_max_nodes\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"5\\\" max=\\\"200\\\" step=\\\"1\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_memory_max_links\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"记忆图谱最多保留多少条关系边。\\\"></span>最大记忆关系数</label>\\r\\n                    <input id=\\\"ai_wbr_memory_max_links\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"0\\\" max=\\\"400\\\" step=\\\"1\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_memory_request_max_tokens\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"后置记忆整理请求实际发送给模型的 max_tokens 上限。普通整理和重试都使用这个值。\\\"></span>后置请求 tokens 上限</label>\\r\\n                    <input id=\\\"ai_wbr_memory_request_max_tokens\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"32\\\" max=\\\"100000\\\" step=\\\"16\\\" />\\r\\n\\r\\n                    <label for=\\\"ai_wbr_memory_retries\\\"><span class=\\\"fa-solid fa-circle-info ai-wbr-help\\\" title=\\\"后置记忆整理失败、空回或解析失败时，额外自动重试几次。\\\"></span>后置记忆重试次数</label>\\r\\n                    <input id=\\\"ai_wbr_memory_retries\\\" class=\\\"text_pole\\\" type=\\\"number\\\" min=\\\"0\\\" max=\\\"10\\\" step=\\\"1\\\" />\\r\\n                </div>\\r\\n\\r\\n                <div class=\\\"ai-wbr-actions\\\">\\r\\n                    <button id=\\\"ai_wbr_memory_run_now\\\" class=\\\"menu_button\\\" type=\\\"button\\\">立即整理本轮</button>\\r\\n                    <button id=\\\"ai_wbr_memory_save_json\\\" class=\\\"menu_button\\\" type=\\\"button\\\">保存 JSON</button>\\r\\n                    <button id=\\\"ai_wbr_memory_clear\\\" class=\\\"menu_button\\\" type=\\\"button\\\">清空记忆</button>\\r\\n                    <span id=\\\"ai_wbr_memory_status\\\" class=\\\"ai-wbr-status\\\">未启用</span>\\r\\n                </div>\\r\\n\\r\\n                <div id=\\\"ai_wbr_memory_graph\\\" class=\\\"ai-wbr-memory-graph\\\"></div>\\r\\n                <div id=\\\"ai_wbr_memory_node_editor\\\" class=\\\"ai-wbr-memory-node-editor\\\"></div>\\r\\n                <div id=\\\"ai_wbr_memory_edge_editor\\\" class=\\\"ai-wbr-memory-edge-editor\\\"></div>\\r\\n                <div id=\\\"ai_wbr_memory_state_editor\\\" class=\\\"ai-wbr-memory-s