// ==UserScript==
// @name         ????? AI Worldbook Router - Tavern Helper?
// @namespace    https://github.com/wominIII/ai-worldbook-router
// @version      0.3.6-userscript.4
// @description  ? SillyTavern ????????????????/??????????
// @author       zmer / converted by Codex
// @match        *://*/*
// @grant        none
// @run-at       document-idle
// ==/UserScript==
(function () {
    'use strict';

    const AI_WBR_INSTANCE_KEY = '__AI_WORLDBOOK_ROUTER_USERSCRIPT_LOADED__';

    function getHostWindow() {
        try {
            if (window.parent && window.parent !== window && window.parent.document) {
                return window.parent;
            }
        } catch (_) {}
        return window;
    }

    const hostWindow = getHostWindow();
    const hostDocument = hostWindow.document;
    if (!hostDocument || hostWindow[AI_WBR_INSTANCE_KEY]) {
        return;
    }
    hostWindow[AI_WBR_INSTANCE_KEY] = true;

